export function getFlowbiteCatalogEntries(group?: string) {
  const entries: readonly FlowbiteCatalogEntry[] = flowbiteCatalog
  if (!group) return flowbiteCatalog
  return entries.filter((entry) => entry.group === group)
}

export function getFlowbiteCatalogGroups() {
  return Array.from(new Set(flowbiteCatalog.map((entry) => entry.group))).sort()
}

export function getCmsMappedFlowbiteCatalogEntries() {
  const entries: readonly FlowbiteCatalogEntry[] = flowbiteCatalog
  return entries.filter((entry) => entry.cmsTemplateId)
}

export function getUnmappedFlowbiteCatalogEntries() {
  const entries: readonly FlowbiteCatalogEntry[] = flowbiteCatalog
  return entries.filter((entry) => !entry.cmsTemplateId)
}
